# [[scripts_downstream/04_visualization.R]]
# Goal: Generate PCA, Volcano, and Heatmap plots for MiaPAca-2 results.

library(DESeq2)
library(ggplot2)
library(EnhancedVolcano)
library(ggVennDiagram)
library(ComplexHeatmap)
library(circlize)
library(tidyverse)
library(org.Hs.eg.db)
library(clusterProfiler)
library(enrichplot)
library(patchwork)

# 1. Load data
# Uses the .RData generated by previous steps
load("./.RData/02_deseq_results.RData")
load("./.RData/03_enrichment_results.RData")

# 1.5 ID Mapping (ENSG -> Symbol)
message("Mapping gene IDs...")
gene_ids <- rownames(dds)
gene_map <- bitr(gene_ids, fromType = "ENSEMBL", toType = "SYMBOL", OrgDb = org.Hs.eg.db) %>%
  distinct(ENSEMBL, .keep_all = TRUE)
row.names(gene_map) <- gene_map$ENSEMBL

# Ensure output directories exist
dir.create("../results/figures", showWarnings = FALSE, recursive = TRUE)

# Transform counts (VST)
vsd <- vst(dds, blind=FALSE)

# 1.6 Create clean Sample Names for display
# Combine Conc. and Replicate to get names like "DMSO_1" or "0.5nM_1"
colData(vsd)$display_name <- paste0(colData(vsd)$Conc., "_", colData(vsd)$Replicate)
colnames(vsd) <- colData(vsd)$display_name

# Order VSD columns by condition (DMSO -> 0.5 -> 1 -> 5)
vsd <- vsd[, order(vsd$condition)]

# Shared dose colour palette (reused across PCA + heatmaps)
cond_levels   <- unique(as.character(colData(vsd)$condition))
dose_palette_shared <- setNames(
  colorRampPalette(RColorBrewer::brewer.pal(min(length(cond_levels), 8), "Set2"))(length(cond_levels)),
  cond_levels
)

p_pca <- plotPCA(vsd, intgroup = "condition") +
  scale_color_manual(values = dose_palette_shared) +
  theme_classic() +
  theme(
    panel.background  = element_rect(fill = "white", color = NA),
    plot.background   = element_rect(fill = "white", color = NA),
    panel.grid.major  = element_line(color = "grey88", linewidth = 0.4),
    panel.grid.minor  = element_line(color = "grey93", linewidth = 0.2)
  ) +
  ggtitle("PCA Plot: MiaPAca-2 Drug Response")

ggsave("../results/figures/04_pca_plot.png", p_pca, width = 8, height = 6, bg = "white")
message("[OK] PCA plot saved -> 04_pca_plot.png  (8x6 in, ", length(cond_levels), " conditions)")

# 3. Multi-dose Volcano Plots -- individual per dose + stitched combined
# Loop through contrasts for all doses
volcano_plots <- list()
for (dose in names(results_list)) {
  message("Generating Volcano for ", dose)
  res_shrunk <- results_list[[dose]]$shrunk
  safe_name <- str_replace_all(dose, "[^a-zA-Z0-9]", "_")
  
  # Map ENSG IDs to Gene Symbols for labels
  ensg_ids <- rownames(res_shrunk)
  sym_labels <- gene_map[ensg_ids, "SYMBOL"]
  sym_labels <- ifelse(is.na(sym_labels), ensg_ids, sym_labels) # fallback to ENSG
  
  # Direction-based custom coloring: Red=Up, Blue=Down, Grey=Not Significant
  res_df <- as.data.frame(res_shrunk)
  pCut <- 0.05; fcCut <- 1.0
  keyvals <- case_when(
    res_df$log2FoldChange >  fcCut & !is.na(res_df$padj) & res_df$padj < pCut ~ "#D62728",
    res_df$log2FoldChange < -fcCut & !is.na(res_df$padj) & res_df$padj < pCut ~ "#1F77B4",
    TRUE ~ "grey60"
  )
  names(keyvals) <- case_when(
    keyvals == "#D62728" ~ "Upregulated",
    keyvals == "#1F77B4" ~ "Downregulated",
    TRUE ~ "Not Significant"
  )
  
  # Gene count summary for subtitle
  n_up   <- sum(keyvals == "#D62728", na.rm = TRUE)
  n_down <- sum(keyvals == "#1F77B4", na.rm = TRUE)
  n_ns   <- sum(keyvals == "grey60",  na.rm = TRUE)
  count_subtitle <- paste0("Up: ", n_up, "  |  Down: ", n_down, "  |  Not Significant: ", n_ns)
  
  p_volcano <- EnhancedVolcano(res_shrunk,
                               lab = sym_labels,
                               x = 'log2FoldChange',
                               y = 'padj',
                               title = paste(dose, 'vs DMSO'),
                               subtitle = count_subtitle,
                               ylab = "-log10(Adjusted p-value)",
                               pCutoff = pCut,
                               FCcutoff = fcCut,
                               colCustom = keyvals,
                               colAlpha = 0.8)
  
  volcano_plots[[dose]] <- p_volcano
  out_vol <- paste0("../results/figures/04_volcano_", safe_name, ".png")
  ggsave(out_vol, p_volcano, width = 10, height = 8, bg = "white")
  message("[OK] Volcano saved  -> 04_volcano_", safe_name, ".png",
          "  |  Up: ", n_up, "  Down: ", n_down, "  NS: ", n_ns)
}

# Stitch all volcano plots side-by-side
if (length(volcano_plots) > 1) {
  combined_volcano <- wrap_plots(volcano_plots, nrow = 1) +
    plot_annotation(
      title = "Volcano Plots: All Concentrations vs DMSO",
      theme = theme(plot.title = element_text(face = "bold", hjust = 0.5))
    )
  ggsave("../results/figures/04_volcano_combined.png",
         combined_volcano, width = 10 * length(volcano_plots), height = 9, bg = "white")
  message("[OK] Combined volcano -> 04_volcano_combined.png",
          "  (", length(volcano_plots), " panels, ", 10 * length(volcano_plots), "x9 in)")
}

# 4. Venn Diagram (3.1a)
# Extract significant gene sets for each dose
sig_list <- lapply(results_list, function(x) {
  rownames(subset(as.data.frame(x$shrunk), padj < 0.05 & abs(log2FoldChange) > 1))
})

# Filter out empty sets if any
sig_list <- sig_list[sapply(sig_list, length) > 0]

if (length(sig_list) >= 2) {
  p_venn <- ggVennDiagram(sig_list) +
    scale_fill_gradient(low = "white", high = "red") +
    ggtitle("Overlap of DEGs across Kromastat Doses")
  
  ggsave("../results/figures/04_venn_diagram_doses.png", p_venn,
         width = 8, height = 8, bg = "white")
  message("[OK] Venn diagram  -> 04_venn_diagram_doses.png",
          "  (", length(sig_list), " dose sets)")
}

# 5. Pathway-specific Heatmap
top_go <- enrichment_results_all[["5nM"]]$ora_go
if (!is.null(top_go)) {
  top_pathways <- top_go@result %>%
    filter(p.adjust < 0.05) %>%
    head(6)

  expanded_matrix_list <- list()
  annotation_row_list  <- list()

  for (i in seq_len(nrow(top_pathways))) {
    path_name  <- top_pathways$Description[i]
    safe_path  <- str_trunc(str_replace_all(path_name, "[^a-zA-Z0-9]", "_"), 30)
    genes_path <- str_split(top_pathways$geneID[i], "/")[[1]]
    genes_path <- intersect(genes_path, rownames(vsd))
    message("Pathway '", path_name, "': ", length(genes_path), " genes found in VSD.")

    if (length(genes_path) > 0) {
      mat_slice <- assay(vsd)[genes_path, , drop = FALSE]
      rownames(mat_slice) <- paste0(genes_path, "__", safe_path)
      expanded_matrix_list[[path_name]] <- mat_slice
      annot_slice <- data.frame(Pathway = rep(path_name, length(genes_path)))
      rownames(annot_slice) <- rownames(mat_slice)
      annotation_row_list[[path_name]] <- annot_slice
    }
  }

  if (length(expanded_matrix_list) > 0) {
    mat_pathway  <- do.call(rbind, expanded_matrix_list)
    df_annot_row <- do.call(rbind, annotation_row_list)
    mat_pathway  <- mat_pathway - rowMeans(mat_pathway)
    mat_pathway  <- pmin(pmax(mat_pathway, -2), 2)

    orig_ensg       <- str_split_i(rownames(mat_pathway), "__", 1)
    symbols_display <- gene_map[orig_ensg, "SYMBOL"]
    labels_display  <- ifelse(is.na(symbols_display), orig_ensg, symbols_display)

    wrapped_pw     <- str_wrap(df_annot_row$Pathway, width = 20)
    pathway_factor <- factor(wrapped_pw, levels = unique(wrapped_pw))

    col_fun <- colorRamp2(c(-2, 0, 2), c("navy", "white", "firebrick3"))

    pathway_names <- levels(pathway_factor)
    n_pw          <- length(pathway_names)
    pw_palette    <- setNames(
      colorRampPalette(RColorBrewer::brewer.pal(min(n_pw, 8), "Set1"))(n_pw),
      pathway_names
    )

    conditions   <- colData(vsd)$condition
    top_ha <- HeatmapAnnotation(
      Dose = as.character(conditions),
      col  = list(Dose = dose_palette_shared),
      show_annotation_name = FALSE,
      show_legend          = FALSE
    )

    right_ha <- rowAnnotation(
      id      = anno_text(labels_display, gp = gpar(fontsize = 7)),
      Pathway = pathway_factor,
      gap     = unit(4, "mm"),
      col     = list(Pathway = pw_palette),
      show_annotation_name = FALSE,
      show_legend          = c(id = FALSE, Pathway = FALSE)
    )

    ht_pathway <- Heatmap(
      mat_pathway,
      name              = "log2FC",
      col               = col_fun,
      row_split         = pathway_factor,
      row_title_side    = "right",
      row_title_rot     = 0,
      row_title_gp      = gpar(fontsize = 8, fontface = "bold"),
      row_gap           = unit(0, "mm"),
      cluster_rows      = FALSE,
      cluster_row_slices = FALSE,
      cluster_columns   = FALSE,
      column_split      = factor(as.character(conditions), levels = unique(as.character(conditions))),
      column_title_gp   = gpar(fontsize = 9, fontface = "bold"),
      column_title_rot  = 0,
      column_gap        = unit(0, "mm"),
      top_annotation    = top_ha,
      right_annotation  = right_ha,
      show_row_names    = FALSE,
      show_column_names = TRUE,
      column_names_rot  = 45,
      column_names_gp   = gpar(fontsize = 10),
      use_raster        = FALSE,
      height            = unit(nrow(mat_pathway) * 6, "mm"),
      width             = unit(ncol(mat_pathway) * 10, "mm"),
      heatmap_legend_param = list(
        title          = "log2(FC)",
        title_position = "leftcenter-rot",
        at             = c(-2, -1, 0, 1, 2),
        labels         = c("-2", "-1", "0", "1", "2"),
        direction      = "vertical",
        legend_height  = unit(4, "cm")
      )
    )

    px_per_mm    <- 150 / 25.4
    mm_legend    <- 0
    mm_title     <- 22
    mm_col_title <- 12
    mm_dose_bar  <- 8
    mm_col_names <- 40
    mm_padding   <- 5
    mm_rows      <- nrow(mat_pathway) * 6
    canvas_h_px  <- round((mm_legend + mm_title + mm_col_title + mm_dose_bar + mm_col_names + mm_padding + mm_rows) * px_per_mm)

    png("../results/figures/04_heatmap_pathway_genes.png",
        width = 1280, height = canvas_h_px, res = 150)
    ht_opt(TITLE_PADDING = unit(c(2, 8), "mm"))
    draw(ht_pathway,
         heatmap_legend_side    = "left",
         annotation_legend_side = "top",
         merge_legend           = FALSE,
         align_heatmap_legend   = "heatmap_top",
         column_title           = "MiaPAca-2: Genes Grouped by Pathway",
         column_title_gp        = gpar(fontsize = 12, fontface = "bold"))
    decorate_annotation("Pathway", {
      grid.text("Pathway",
                x    = unit(0, "npc"),
                y    = unit(1, "npc") + unit(3, "mm"),
                just = c("left", "bottom"),
                gp   = gpar(fontsize = 9, fontface = "bold"))
    })
    dev.off()
    message("[OK] Pathway heatmap -> 04_heatmap_pathway_genes.png",
            "  (", nrow(mat_pathway), " rows x ", ncol(mat_pathway), " cols",
            "  |  ", nlevels(pathway_factor), " pathways",
            "  |  canvas: 1280x", canvas_h_px, "px)")
  }
}

# 6. Default Heatmap (Top 50 Variable) with ComplexHeatmap
