     align_heatmap_legend   = "heatmap_top",
     column_title           = "Top 50 Most Variable Genes",
     column_title_gp        = gpar(fontsize = 12, fontface = "bold"))
dev.off()
message("[OK] Top-var heatmap  -> 04_heatmap_top_variable.png",
        "  (", nrow(mat_var), " rows x ", ncol(mat_var), " cols",
        "  |  canvas: 1280x", canvas_h_var, "px)")

# 7. Hallmark NES Barplots -- individual per dose + stitched combined
message("Building Hallmark NES plots...")

# Helper: build a single NES barplot for one dose
make_nes_plot <- function(hallmark_res, dose_label) {
  hall_df <- as.data.frame(hallmark_res) %>%
    mutate(Response = ifelse(NES > 0, "Activated", "Suppressed")) %>%
    arrange(Response, ifelse(Response == "Activated", NES, -NES)) %>%
    mutate(Description = factor(Description, levels = unique(Description)))
  
  ggplot(hall_df, aes(x = NES, y = Description, fill = Response)) +
    geom_col(width = 0.75) +
    scale_fill_manual(
      values = c("Activated" = "#D62728", "Suppressed" = "#1F77B4"),
      name = "Direction"
    ) +
    facet_grid(Response ~ ., scales = "free_y", space = "free_y") +
    geom_vline(xintercept = 0, linewidth = 0.4, color = "grey30") +
    theme_bw(base_size = 11) +
    theme(
      strip.text.y = element_text(angle = -90, face = "bold"),
      strip.background = element_rect(fill = "grey88"),
      panel.grid.major.y = element_blank(),
      axis.text.y = element_text(size = 8),
      plot.title = element_text(size = 11, face = "bold", hjust = 0.5)
    ) +
    labs(
      title = dose_label,
      x = "Normalized Enrichment Score (NES)", y = NULL
    )
}

nes_plots <- list()
for (dose in names(enrichment_results_all)) {
  hallmark_res <- enrichment_results_all[[dose]]$gsea_hallmark
  if (!is.null(hallmark_res) && nrow(as.data.frame(hallmark_res)) > 0) {
    safe_name <- str_replace_all(dose, "[^a-zA-Z0-9]", "_")
    p <- make_nes_plot(hallmark_res, paste0("Hallmark NES: ", dose))
    nes_plots[[dose]] <- p
    
    # Save individual plot
    n_rows <- nrow(as.data.frame(hallmark_res))
    ggsave(
      paste0("../results/figures/04_hallmark_nes_", safe_name, ".png"),
      p, width = 10, height = max(6, n_rows * 0.38)
    )
  }
}

# Save stitched combined NES plot (side-by-side: 0.5nM | 1nM | 5nM)
if (length(nes_plots) > 1) {
  combined_nes <- wrap_plots(nes_plots, nrow = 1) +
    plot_annotation(title = "Hallmark NES: All Concentrations",
                    theme = theme(plot.title = element_text(face = "bold", hjust = 0.5)))
  ggsave("../results/figures/04_hallmark_nes_combined.png",
         combined_nes, width = 10 * length(nes_plots), height = 12)
}

# 8. GSEA Dotplots -- individual per dose + stitched combined
message("Building GSEA dotplots...")

# Collect GSEA results across all doses
gsea_combined <- map2_dfr(
  enrichment_results_all,
  names(enrichment_results_all),
  function(res, dose_name) {
    gsea_res <- res$gsea_go
    if (!is.null(gsea_res) && nrow(as.data.frame(gsea_res)) > 0) {
      as.data.frame(gsea_res) %>%
        dplyr::select(Description, NES, pvalue, p.adjust, setSize) %>%
        mutate(
          Dose = dose_name,
          Response = ifelse(NES > 0, "activated", "suppressed")
        )
    }
  }
)

# Helper: build a single GSEA dotplot for one dose
make_gsea_plot <- function(df_dose, dose_label, top_paths_wrapped) {
  df_dose <- df_dose %>%
    filter(Description %in% top_paths_wrapped) %>%
    mutate(
      Description = factor(Description, levels = rev(top_paths_wrapped)),
      Response = factor(Response, levels = c("activated", "suppressed"))
    )
  
  ggplot(df_dose, aes(x = Response, y = Description,
                      color = pvalue, size = setSize)) +
    geom_point(alpha = 0.9) +
    # Red = most significant (low pvalue), Blue = less significant (high pvalue)
    scale_color_gradient(
      low = "#D62728", high = "#1F77B4",
      name = "pvalue"
    ) +
    scale_size_continuous(name = "Count", range = c(3, 11)) +
    # Vertical divider between activated and suppressed
    geom_vline(xintercept = 1.5, color = "grey40", linewidth = 0.6) +
    theme_bw(base_size = 10) +
    theme(
      axis.text.x = element_text(size = 9),
      axis.text.y = element_text(size = 9, hjust = 1),
      strip.background = element_rect(fill = "#2F6F8E"),
      strip.text = element_text(color = "white", face = "bold", size = 11),
      panel.grid.major.x = element_blank(),
      plot.title = element_text(hjust = 0.5, face = "bold", size = 11)
    ) +
    labs(title = paste0("Enrichment GSEA: ", dose_label),
         x = NULL, y = NULL) +
    guides(
      color = guide_colorbar(order = 1, title = "pvalue"),
      size  = guide_legend(order = 2, title = "Count")
    )
}

if (!is.null(gsea_combined) && nrow(gsea_combined) > 0) {
  # Get globally consistent top pathways (union across all doses)
  top_paths <- gsea_combined %>%
    group_by(Description) %>%
    summarise(min_pval = min(pvalue)) %>%
    arrange(min_pval) %>%
    head(25) %>%
    pull(Description)
  top_paths_wrapped <- str_wrap(top_paths, width = 35)
  
  gsea_combined <- gsea_combined %>%
    mutate(Description = str_wrap(Description, width = 35))
  
  gsea_plots <- list()
  for (dose in levels(factor(gsea_combined$Dose, levels = c("0.5nM (500pM)", "1nM", "5nM")))) {
    df_dose <- gsea_combined %>% filter(Dose == dose)
    if (nrow(df_dose) > 0) {
      safe_name <- str_replace_all(dose, "[^a-zA-Z0-9]", "_")
      p <- make_gsea_plot(df_dose, dose, top_paths_wrapped)
      gsea_plots[[dose]] <- p
      
      # Save individual plot
      ggsave(
        paste0("../results/figures/04_gsea_dotplot_", safe_name, ".png"),
        p, width = 7, height = max(6, length(top_paths) * 0.45)
      )
    }
  }
  
  # Save stitched combined GSEA plot
  if (length(gsea_plots) > 1) {
    combined_gsea <- wrap_plots(gsea_plots, nrow = 1, guides = "collect") +
      plot_annotation(
        title = "GSEA: Multi-Dose Comparison",
        theme = theme(plot.title = element_text(face = "bold", hjust = 0.5))
      )
    ggsave(
      "../results/figures/04_gsea_dotplot_combined.png",
      combined_gsea,
      width = 7 * length(gsea_plots) + 2,
      height = max(8, length(top_paths) * 0.45)
    )
  }
}

message("Visualization complete. All plots saved to ../results/figures/")
